//! Typed identifiers for the Educore engine.
//!
//! Every aggregate and every cross-cutting concept is keyed by a typed
//! identifier. Two identifiers that share the same underlying UUID but
//! have different Rust types (e.g. `SchoolId` vs. `UserId`) are
//! **not** interchangeable: the type system catches cross-aggregate id
//! confusion at compile time.
//!
//! All identifiers are UUIDv7 (time-ordered, globally unique). They are
//! generated by the [`IdGenerator`](crate::id_gen::IdGenerator) port
//! and are opaque to consumers — strings are never parsed.
//!
//! See:
//! - `docs/schemas/tenancy-schema.md` § 2 (SchoolId)
//! - `docs/schemas/event-schema.md` § 1.1 (EventId, CorrelationId)
//! - `docs/schemas/command-schema.md` § 1.2 (IdempotencyKey)

use std::fmt;
use std::hash::Hash;

use serde::{Deserialize, Serialize};
use uuid::Uuid;

use crate::error::{DomainError, Result};

/// The actor that triggered a state change.
///
/// Per `docs/schemas/database-schema.md` § 5 and `docs/schemas/event-schema.md`
/// § 1.1, system-inserted rows (bootstrap, migrations, scheduled jobs) use a
/// well-known id; everything else uses a real `UserId`.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(transparent)]
pub struct UserId(pub Uuid);

/// The tenant root. A `SchoolId` is the unit of tenancy; every other
/// aggregate anchors to a `SchoolId` (either as part of its typed
/// identifier or as a separate column).
///
/// Per `docs/schemas/tenancy-schema.md` § 2: immutable for the lifetime
/// of the school; opaque to consumers; UUIDv7.
///
/// Aggregates that belong to a school embed `SchoolId` in their typed
/// identifier (e.g. `StudentId(SchoolId, Uuid)`) so that
/// cross-tenant references become compile-time errors.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, PartialOrd, Ord, Serialize, Deserialize)]
#[serde(transparent)]
pub struct SchoolId(pub Uuid);

/// A domain event identifier.
///
/// Per `docs/schemas/event-schema.md` § 1.1: UUIDv7, the canonical
/// primary key of the event in the log. Two events MUST NOT share an
/// `EventId`.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, PartialOrd, Ord, Serialize, Deserialize)]
#[serde(transparent)]
pub struct EventId(pub Uuid);

/// A correlation identifier: the id of the request or workflow that
/// initiated the chain of events.
///
/// Per `docs/schemas/event-schema.md` § 1.1: set by the inbound
/// command, propagated through every event in the same request.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, PartialOrd, Ord, Serialize, Deserialize)]
#[serde(transparent)]
pub struct CorrelationId(pub Uuid);

/// A session identifier.
///
/// Optional in `TenantContext`. Carries the consumer's session
/// boundary (which may differ from the request's correlation).
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(transparent)]
pub struct SessionId(pub Uuid);

/// A caller-provided idempotency token.
///
/// Per `docs/schemas/command-schema.md` § 1.2 and
/// `docs/decisions/ADR-014-Idempotency.md`: two commands with the same
/// `IdempotencyKey` against the same `school_id` and `command_type`
/// MUST produce the same result and emit no additional events on
/// replay.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(transparent)]
pub struct IdempotencyKey(pub Uuid);

/// Marker trait for typed identifiers.
///
/// Implemented by every wrapper around `Uuid` in this module. The
/// trait exists so generic code (e.g. `StudentId(SchoolId, Uuid)`)
/// can constrain its inner school id without naming a specific
/// concrete type.
pub trait Identifier: Clone + Copy + PartialEq + Eq + Hash + fmt::Debug + fmt::Display {
    /// Returns the inner UUID.
    fn as_uuid(&self) -> Uuid;

    /// Returns a new typed identifier wrapping the given UUID.
    ///
    /// Constructors are infallible at the type level; if the caller
    /// wants to validate (e.g. "is this a v7 UUID?") they call
    /// [`from_uuid_checked`].
    fn from_uuid(uuid: Uuid) -> Self;

    /// Constructs a typed identifier from a UUID, validating that
    /// the UUID is a v7 (time-ordered) value.
    ///
    /// Returns `Err(DomainError::Validation)` if the UUID is not v7.
    fn from_uuid_checked(uuid: Uuid) -> Result<Self> {
        if uuid.get_version_num() == 7 {
            Ok(Self::from_uuid(uuid))
        } else {
            Err(DomainError::Validation(format!(
                "expected UUIDv7 identifier, got version {}",
                uuid.get_version_num()
            )))
        }
    }
}

impl Identifier for UserId {
    #[inline]
    fn as_uuid(&self) -> Uuid {
        self.0
    }
    #[inline]
    fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }
}

