/// The well-known system actor used for system-inserted rows, jobs,
/// and migrations. Per `docs/schemas/database-schema.md` § 5 the
/// constant is named `SYSTEM_USER_ID`.
///
/// A v7 UUID with all-zero timestamp and a fixed random suffix so
/// the id is recognisable in logs and the audit trail. The value is
/// stable for the lifetime of the engine — consumers that need to
/// compare against "this was a system change" should reference this
/// constant rather than the literal.
pub const SYSTEM_USER_ID: UserId = UserId(Uuid::from_bytes([
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x70, 0x00, 0x80, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x01,
]));

/// The well-known "platform" school id used for global aggregates
/// (e.g. `Country`, `Currency` lookup tables) that are not anchored
/// to a single school.
///
/// Per `docs/specs/platform/overview.md` invariants: aggregates
/// without a school are global; the platform school id is the
/// anchor for those rows.
pub const PLATFORM_SCHOOL_ID: SchoolId = SchoolId(Uuid::from_bytes([
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x70, 0x00, 0x80, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x02,
]));

#[cfg(test)]
#[allow(
    clippy::unwrap_used,
    clippy::expect_used,
    clippy::panic,
    clippy::dbg_macro
)]
mod tests {
    use super::*;

    #[test]
    fn from_uuid_checked_accepts_v7() {
        let v7 = Uuid::now_v7();
        let id = SchoolId::from_uuid_checked(v7).unwrap();
        assert_eq!(id.as_uuid(), v7);
    }

    #[test]
    fn from_uuid_checked_rejects_v4() {
        let v4 = Uuid::new_v4();
        let err = SchoolId::from_uuid_checked(v4).unwrap_err();
        assert!(matches!(err, DomainError::Validation(_)));
    }

    #[test]
    fn system_user_id_is_stable() {
        let a = SYSTEM_USER_ID.as_uuid();
        let b = Uuid::from_bytes([
            0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x70, 0x00, 0x80, 0x00, 0x00, 0x00, 0x00, 0x00,
            0x00, 0x01,
        ]);
        assert_eq!(a, b);
        assert_eq!(a.get_version_num(), 7);
    }

    #[test]
    fn platform_school_id_is_stable() {
        let a = PLATFORM_SCHOOL_ID.as_uuid();
        let b = Uuid::from_bytes([
            0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x70, 0x00, 0x80, 0x00, 0x00, 0x00, 0x00, 0x00,
            0x00, 0x02,
        ]);
        assert_eq!(a, b);
        assert_eq!(a.get_version_num(), 7);
    }

    #[test]
    fn display_matches_inner_uuid() {
        let v7 = Uuid::now_v7();
        let id = SchoolId::from_uuid(v7);
        assert_eq!(id.to_string(), v7.to_string());
    }
}
